import { React, useState } from 'react'
import Button from '@mui/material/Button';
import { FormControl, Stack, Box, InputLabel, Input, IconButton, InputAdornment, Typography, Link } from '@mui/material';
import Visibility from '@mui/icons-material/Visibility';
import VisibilityOff from '@mui/icons-material/VisibilityOff';
import { Link as RouterLink, useNavigate } from 'react-router-dom'
import useAuth from '../hooks/useAuth'
import appTheme from '../theme';



const LoginForm = () => {
    
    const [showPassword, setShowPassword] = useState(false);
  
    const handleClickShowPassword = () => setShowPassword((show) => !show);
  
    const handleMouseDownPassword = (event) => {
      event.preventDefault();
    };

    const { user, logIn, dataUser } = useAuth()

    const navigate = useNavigate()

    const [error, setError ] = useState()

    


    const handleSubmit = async(e) => {

        e.preventDefault()

        setError('')

        try {

            await logIn(user)
            
            

        } catch(error) {

            if ( error.code === "auth/user-not-found")
            {
                setError('El usuario ingresado no existe.');
            } else if ( error.code === "auth/wrong-password")
            {
                setError('La contraseña no es correcta.');
            } else if ( error.code === "auth/internal-error")
            {
                setError('Se debe ingresar la contraseña.');
            } else if ( error.code === "auth/invalid-email")
            {
                setError('Se debe ingresar un mail válido.');
            } else
            {
                setError('Se produjo un error. Volvé a intentar más tarde.');
            }
                
        }
        
    }
    

  return (
        <>
        {   
            <Stack direction="column" sx={{
                    display: 'flex',
                    alignItems: 'center',
                }}>
                <form onSubmit={handleSubmit}>
                    <Box sx={{
                            margin: '5rem auto',
                            padding: '1rem',
                        }}>

                        <FormControl variant="standard" sx={{
                            width: '100%',
                            paddingBottom: '2rem',
                        }}  >
                        <InputLabel sx={{
                            fontSize: '14px',
                            color: appTheme.palette.primary.main,
                        
                        }} htmlFor="email">Email</InputLabel>
                        <Input
                            id="email"
                            type="text"
                            onChange={dataUser}
                            name="email"
                        />
                        </FormControl>
                        <FormControl sx={{ width: '100%' }} variant="standard" >
                        <InputLabel sx={{
                            fontSize: '14px',
                            color: appTheme.palette.primary.main,
                        
                        }} htmlFor="password">Password</InputLabel>
                        <Input
                            id="password"
                            name="password"
                            type={showPassword ? 'text' : 'password'}
                            endAdornment={
                            <InputAdornment position="end">
                                <IconButton
                                aria-label="toggle password visibility"
                                onClick={handleClickShowPassword}
                                onMouseDown={handleMouseDownPassword}
                                color="primary"
                                >
                                {showPassword ? <VisibilityOff /> : <Visibility />}
                                </IconButton>
                            </InputAdornment>
                            }
                            onChange={dataUser}
                        />
                        </FormControl>
                    </Box>
                    <Box>
                        <Typography align="center" variant='subtitle2' color="primary.dark">¿No tenés una cuenta? <Link component={RouterLink} color="primary.dark" fontWeight={700} to="/register" >Registrate</Link></Typography>
                        
                    </Box>
                    
                    <Button variant="contained" sx={{
                        textTransform: 'capitalize',
                        fontSize: '18px',
                        fontFamily: 'Poppins',
                        fontWeight: 700,
                        width: '100%',
                        marginTop: '6rem',
                        marginBottom: '1rem'
                    }} type="submit">Ingresar</Button>
                </form>
            </Stack>            
}           
        </>
  )
}

export default LoginForm
